import React from "react";
import { Outlet, Link, useLocation } from "react-router-dom";

const AdminLayout = () => {
  const location = useLocation();

  const navItems = [
    { name: "Tổng quan", path: "/admin/dashboard", icon: "📊" },
    { name: "Quản lý sản phẩm", path: "/admin/products", icon: "🛍️" },
    { name: "Quản lý đơn hàng", path: "/admin/orders", icon: "📦" },
    { name: "Quản lý danh mục", path: "/admin/categories", icon: "🗂️" },
    { name: "Quản lý người dùng", path: "/admin/users", icon: "👤" },
  ];

  const currentPage = location.pathname.replace("/admin/", "").toUpperCase();
  const isDashboard = location.pathname === "/admin/dashboard";

  return (
    <div className="flex min-h-screen font-sans bg-background text-[14px] leading-relaxed">
      {/* Sidebar */}
      <aside className="fixed left-0 top-0 bottom-0 w-52 bg-primary/20 border-r border-accent/30 flex flex-col shadow-sm z-50">
        {/* Logo */}
        <Link
          to="/"
          className="flex items-center gap-3 p-4 border-b border-accent/40 hover:bg-primary/30 transition"
        >
          <div className="w-9 h-9 rounded-full bg-primary flex items-center justify-center text-secondary font-bold shadow">
            A
          </div>
          <div>
            <p className="text-sm font-semibold text-secondary">Admin</p>
            <p className="text-xs text-accent font-medium">DTP Flower</p>
          </div>
        </Link>

        {/* Navigation */}
        <nav className="flex flex-col gap-1 p-2 flex-1">
          {navItems.map((item) => (
            <Link
              key={item.path}
              to={item.path}
              className={`flex items-center gap-2 px-4 py-2 rounded-md text-sm transition-all duration-200 ${
                location.pathname === item.path
                  ? "bg-accent/20 text-secondary font-semibold border-l-4 border-accent"
                  : "text-secondary/70 hover:bg-primary/30 hover:text-secondary"
              }`}
            >
              <span>{item.icon}</span>
              {item.name}
            </Link>
          ))}
        </nav>

        {/* Xem trang web */}
        <div className="p-3">
          <a
            href="/"
            className="block text-center bg-accent text-secondary py-2 rounded-md text-sm font-semibold hover:bg-accent/80 transition"
          >
            🌸 Xem trang web
          </a>
        </div>
      </aside>

      {/* Main content */}
      <main
        className={`flex-1 ml-52 p-6 overflow-y-auto transition-colors duration-300 ${
          isDashboard ? "bg-background" : "bg-background/80"
        }`}
      >
        <div className="flex justify-between items-center mb-5">
          <h1
            className={`text-lg font-semibold ${
              isDashboard ? "text-secondary" : "text-secondary/80"
            }`}
          >
            {currentPage || "DASHBOARD"}
          </h1>
        </div>

        <div
          className={`p-5 rounded-lg shadow-md min-h-[70vh] bg-white/90 border border-accent/20`}
        >
          <Outlet />
        </div>
      </main>
    </div>
  );
};

export default AdminLayout;
